SELECT
	count(1) totalCount
FROM MST.TB_USER_CONN_HIST A
WHERE
	A.suser_id = #{suserId, jdbcType=VARCHAR}
	AND (TO_CHAR(A.dlogin_dt ,'YYYY-MM-DD') = TO_CHAR(NOW(),'YYYY-MM-DD'))
	AND A.suser_hndset_id = #{sConnIP, jdbcType=VARCHAR}
